"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState } from "react";
import { X, ArrowRight, CheckCircle2 } from "lucide-react";

interface WaitlistModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function WaitlistModal({ isOpen, onClose }: WaitlistModalProps) {
  const [step, setStep] = useState(1);
  const [email, setEmail] = useState("");

  const handleNext = () => setStep((s) => s + 1);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Here we would typically send to Klaviyo/Shopify
    setStep(4);
    setTimeout(() => {
      onClose();
      // Reset after close
      setTimeout(() => setStep(1), 500);
    }, 3000);
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6">
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-background/80 backdrop-blur-xl"
          />

          {/* Modal Content */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ type: "spring", damping: 25, stiffness: 300 }}
            className="relative w-full max-w-md bg-surface border border-border/50 rounded-2xl shadow-2xl overflow-hidden"
          >
            {/* Close Button */}
            <button
              onClick={onClose}
              className="absolute top-4 right-4 text-secondary hover:text-primary transition-colors z-10"
            >
              <X className="w-5 h-5" />
            </button>

            <div className="p-8">
              <AnimatePresence mode="wait">
                {step === 1 && (
                  <motion.div
                    key="step-1"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex flex-col"
                  >
                    <span className="text-xs tracking-widest text-accent mb-2 uppercase">Step 01</span>
                    <h2 className="text-2xl font-light text-primary mb-6">What is your primary longevity goal?</h2>
                    
                    <div className="space-y-3">
                      {["Deep Sleep & Recovery", "Sustained Cognitive Focus", "Cellular Energy", "Gut Health & Immunity"].map((obs) => (
                        <button
                          key={obs}
                          onClick={handleNext}
                          className="w-full text-left px-5 py-4 rounded-xl border border-border hover:border-accent hover:bg-accent/5 transition-all text-secondary hover:text-primary flex justify-between items-center group"
                        >
                          <span className="font-light">{obs}</span>
                          <ArrowRight className="w-4 h-4 opacity-0 group-hover:opacity-100 transition-opacity text-accent" />
                        </button>
                      ))}
                    </div>
                  </motion.div>
                )}

                {step === 2 && (
                  <motion.div
                    key="step-2"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex flex-col"
                  >
                    <span className="text-xs tracking-widest text-accent mb-2 uppercase">Step 02</span>
                    <h2 className="text-2xl font-light text-primary mb-6">Do you currently invest in premium supplements?</h2>
                    
                    <div className="space-y-3">
                      {["Yes, regularly", "Occasionally", "I'm looking to start"].map((ans) => (
                        <button
                          key={ans}
                          onClick={handleNext}
                          className="w-full text-left px-5 py-4 rounded-xl border border-border hover:border-accent hover:bg-accent/5 transition-all text-secondary hover:text-primary"
                        >
                          <span className="font-light">{ans}</span>
                        </button>
                      ))}
                    </div>
                  </motion.div>
                )}

                {step === 3 && (
                  <motion.div
                    key="step-3"
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    className="flex flex-col"
                  >
                    <span className="text-xs tracking-widest text-accent mb-2 uppercase">Final Step</span>
                    <h2 className="text-2xl font-light text-primary mb-3">Request Founders Access</h2>
                    <p className="text-secondary text-sm font-light leading-relaxed mb-6">
                      We are opening 500 spots for our first Italian drop. Enter your email to secure priority access.
                    </p>
                    
                    <form onSubmit={handleSubmit} className="flex flex-col space-y-4">
                      <input
                        type="email"
                        required
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        placeholder="Your absolute best email..."
                        className="w-full bg-background border border-border rounded-xl px-5 py-4 text-primary placeholder:text-secondary/50 focus:outline-none focus:border-accent/50 focus:ring-1 focus:ring-accent/50 transition-all font-light"
                      />
                      <button
                        type="submit"
                        className="w-full bg-primary text-background font-medium py-4 rounded-xl hover:opacity-90 transition-opacity"
                      >
                        Join The Waitlist
                      </button>
                    </form>
                  </motion.div>
                )}

                {step === 4 && (
                  <motion.div
                    key="step-4"
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="flex flex-col items-center justify-center py-8 text-center"
                  >
                    <motion.div
                      initial={{ scale: 0 }}
                      animate={{ scale: 1 }}
                      transition={{ type: "spring", delay: 0.2 }}
                    >
                      <CheckCircle2 className="w-16 h-16 text-accent mb-6" />
                    </motion.div>
                    <h2 className="text-2xl font-light text-primary mb-2">Access Requested</h2>
                    <p className="text-secondary font-light">
                      Check your inbox shortly. We've reserved your spot.
                    </p>
                  </motion.div>
                )}
              </AnimatePresence>
            </div>
            
            {/* Progress Bar Container at bottom */}
            {step < 4 && (
               <div className="h-1 w-full bg-background relative mt-auto">
                 <motion.div 
                   className="absolute top-0 left-0 h-full bg-accent"
                   initial={{ width: `${((step - 1) / 3) * 100}%` }}
                   animate={{ width: `${(step / 3) * 100}%` }}
                   transition={{ duration: 0.5 }}
                 />
               </div>
            )}
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}
